solution_script:
export interface LoggerContract {
  log(msg: string): void;
}

export class CloudLogger implements LoggerContract {
  log(msg: string) { /* envia a nube */ }
}

export class AppService {
  constructor(private readonly logger: LoggerContract) {}
  doTask() { this.logger.log('Done'); }
}

export function bootstrap() {
  const logger = new CloudLogger();
  return new AppService(logger);
}
